import { CRABS_Base } from "./base";
import { ModSDKModAPI } from "bondage-club-mod-sdk";
import { i18n, LanguageCode } from "../localization";

const DEFAULT_SETTINGS: CRABS_Settings = {
	language: "en",
	overrideLanguage: false,
	showBanner: true,
	rosterOpensDrawer: true,
	hideDrawerTab: false,
	immersiveBlind: false,
	immersiveGag: false,
	respectBcxRules: false,
	compactDrawer: true,
	closeDrawerOnWhisper: false,
	closeDrawerOnChat: false,
	disableDrawer: false,
	lockImmersive: false,
	showMapCompass: true,
	mapSuperZoom: false,
};

/**
 * Combined Settings and UI Manager for CRABS.
 */
export class Settings extends CRABS_Base {
	/** Singleton instance of the Settings module. */
	public static instance: Settings;
	/** The current settings data. */
	public data: CRABS_Settings;
	/** List of UI elements to be rendered in the settings screen. */
	private elements: UIElement[] = [];
	/** Key used for storing settings in local storage. */
	private readonly STORAGE_KEY = "CRABS_Settings";

	// Layout Constants
	/** X coordinate for the left column of settings. */
	private readonly LEFT_COL_X = 550;
	/** X coordinate for the right column of settings. */
	private readonly RIGHT_COL_X = 1250;
	/** X offset for checkboxes within a column. */
	private readonly CHECKBOX_X_OFFSET = 30;
	/** X offset for labels within a column. */
	private readonly LABEL_X_OFFSET = 120;
	/** Width and height of checkboxes. */
	private readonly CHECKBOX_WIDTH = 64;
	/** Vertical spacing between settings elements. */
	//private readonly SPACING_Y = 75;

	/**
	 * Creates an instance of the Settings module.
	 * 
	 * @param {ModSDKModAPI} CRABS - The ModSDK API instance.
	 */
	constructor(CRABS: ModSDKModAPI) {
		super(CRABS);
		Settings.instance = this;
		this.data = this.load();
		this.setupUI();
		this.registerExtension();
	}

	/**
	 * Loads settings from local storage, falling back to defaults if necessary.
	 * 
	 * @returns {CRABS_Settings} The loaded settings.
	 */
	private load(): CRABS_Settings {
		const saved = localStorage.getItem(this.STORAGE_KEY);
		if (saved) {
			try {
				const settings = { ...DEFAULT_SETTINGS, ...JSON.parse(saved) };
				// Use override if checked, otherwise detect game language
				if (!settings.overrideLanguage) {
					settings.language = i18n.detectGameLanguage();
				}
				i18n.setLanguage(settings.language);
				return settings;
			} catch (error) {
				console.error("CRABS: Failed to parse settings", error);
			}
		}
		const defaultSettings = { ...DEFAULT_SETTINGS };
		defaultSettings.language = i18n.detectGameLanguage();
		i18n.setLanguage(defaultSettings.language);
		return defaultSettings;
	}

	/**
	 * Saves the current settings to local storage.
	 * 
	 * @returns {void}
	 */
	public save(): void {
		// Before saving, ensure language is correct if not overriding
		if (!this.data.overrideLanguage) {
			this.data.language = i18n.detectGameLanguage();
		}
		localStorage.setItem(this.STORAGE_KEY, JSON.stringify(this.data));
		i18n.setLanguage(this.data.language);
	}

	/**
	 * Checks if the player is currently restricted (restrained).
	 * 
	 * @returns {boolean} True if restrained, false otherwise.
	 */
	private isRestricted(): boolean {
		return (window as any).Player.IsRestrained?.() || false;
	}

	/**
	 * Initializes the list of UI elements for the settings screen.
	 * 
	 * @returns {void}
	 */
	private setupUI(): void {
		this.elements = [];

		// Category: Language (New Section)
		this.addCheckbox(
			i18n.get("Setting_OverrideLanguage"),
			"overrideLanguage",
			i18n.get("Hint_OverrideLanguage"),
			{ category: "Language", yPos: 200 }
		);

		this.addBackNext(
			i18n.get("Language"),
			"language",
			i18n.get("Hint_Language"),
			["en", "fr", "ru", "zh", "zh_tw", "uk"],
			{
				category: "Language",
				yPos: 275,
				grayedOut: () => !this.data.overrideLanguage
			}
		);

		// Category: Banner (Left Col) - SHIFTED DOWN
		this.addCheckbox(
			i18n.get("Setting_ShowBanner"),
			"showBanner",
			i18n.get("Hint_ShowBanner"),
			{ category: "Banner", yPos: 430 }
		);

		// Category: Drawer (Left Col) - SHIFTED DOWN
		this.addCheckbox(
			i18n.get("Setting_DisableDrawer"),
			"disableDrawer",
			i18n.get("Hint_DisableDrawer"),
			{ category: "Drawer", yPos: 575 }
		);

		const drawerDisabled = () => this.data.disableDrawer;

		this.addCheckbox(
			i18n.get("Setting_RosterTogglesDrawer"),
			"rosterOpensDrawer",
			i18n.get("Hint_RosterTogglesDrawer"),
			{ category: "Drawer", yPos: 650, grayedOut: drawerDisabled }
		);
		this.addCheckbox(
			i18n.get("Setting_HideDrawerTab"),
			"hideDrawerTab",
			i18n.get("Hint_HideDrawerTab"),
			{ category: "Drawer", yPos: 725, grayedOut: () => drawerDisabled() || !this.data.rosterOpensDrawer }
		);
		this.addCheckbox(
			i18n.get("Setting_CompactHeight"),
			"compactDrawer",
			i18n.get("Hint_CompactHeight"),
			{ category: "Drawer", yPos: 800, grayedOut: drawerDisabled }
		);

		// Category: Immersion (Right Col)
		this.addCheckbox(
			i18n.get("Setting_HardcoreLock"),
			"lockImmersive",
			i18n.get("Hint_HardcoreLock"),
			{ category: "Immersion", yPos: 200, grayedOut: () => this.data.lockImmersive && this.isRestricted() }
		);

		const isLocked = (setting: keyof CRABS_Settings) => {
			return () => this.data.lockImmersive && this.isRestricted() && this.data[setting] === true;
		};

		this.addCheckbox(
			i18n.get("Setting_RespectBlindness"),
			"immersiveBlind",
			i18n.get("Hint_RespectBlindness"),
			{ category: "Immersion", yPos: 275, grayedOut: isLocked("immersiveBlind") }
		);
		this.addCheckbox(
			i18n.get("Setting_RespectGags"),
			"immersiveGag",
			i18n.get("Hint_RespectGags"),
			{ category: "Immersion", yPos: 350, grayedOut: isLocked("immersiveGag") }
		);
		this.addCheckbox(
			i18n.get("Setting_RespectBcxRules"),
			"respectBcxRules",
			i18n.get("Hint_RespectBcxRules"),
			{ category: "Immersion", yPos: 425, grayedOut: isLocked("respectBcxRules") }
		);

		// Category: Maps (Right Col)
		this.addCheckbox(
			i18n.get("Setting_ShowMapCompass"),
			"showMapCompass",
			i18n.get("Hint_ShowMapCompass"),
			{ category: "Maps", yPos: 570 }
		);
		this.addCheckbox(
			i18n.get("Setting_SuperZoom"),
			"mapSuperZoom",
			i18n.get("Hint_SuperZoom"),
			{ category: "Maps", yPos: 645 }
		);
	}

	/**
	 * Adds a checkbox element to the settings UI list.
	 * * @param text - The label text for the checkbox.
	 * @param setting - The setting key associated with this checkbox.
	 * @param hint - The tooltip/hint text for the setting.
	 * @param options - Additional configuration options for the checkbox.
	 */
	private addCheckbox(text: string, setting: keyof CRABS_Settings & string, hint: string, options?: Partial<CheckboxElement>) {
		const element: CheckboxElement = {
			type: 'Checkbox',
			text,
			setting,
			hint,
			yPos: options?.yPos || 280,
			width: this.CHECKBOX_WIDTH,
			height: this.CHECKBOX_WIDTH,
			xModifier: 0,
			yModifier: 0,
			category: options?.category
		};
		this.elements.push(element);
	}

	private addBackNext(text: string, setting: keyof CRABS_Settings & string, hint: string, backNextOptions: string[], options?: Partial<BackNextElement>) {
		const element: BackNextElement = {
			type: 'BackNext',
			text,
			setting,
			hint,
			backNextOptions,
			index: backNextOptions.indexOf((this.data as any)[setting]),
			yPos: options?.yPos || 280,
			width: 450,
			height: 64,
			category: options?.category
		};
		this.elements.push(element);
	}

	/**
	 * Registers the CRABS settings screen as an extension in the game.
	 * 
	 * @returns {void}
	 */
	private registerExtension(): void {
		// Assign the definition directly to the shared static base property
		CRABS_Base.subscreenDef = {
			Identifier: "CRABS",
			ButtonText: "CRABS",
			Image: "https://sin-1337.github.io/CRABS/images/CRABS_Logo.png",
			click: () => this.click(),
			run: () => {
				this.setupUI(); // Re-setup UI to refresh localized strings if language changed
				this.draw();
			},
			exit: () => {
				const globalWindow = window as any;
				globalWindow.PreferenceMessage = "";
				if (typeof globalWindow.PreferenceSubscreenExtensionsClear === "function") {
					try { globalWindow.PreferenceSubscreenExtensionsClear(); } catch (error) { }
				}

				// Send the user back to the Extensions menu
				if (typeof globalWindow.PreferenceOpenSubscreen === "function") {
					globalWindow.PreferenceOpenSubscreen("Extensions");
				}
				return false; // Blocks the default exit
			},
			load: () => {
				(window as any).PreferenceMessage = "";
			}
		};

		const waitForFunc = () => {
			const globalWindow = window as any;
			if (typeof globalWindow.PreferenceRegisterExtensionSetting === "function") {
				// Pass the static object to the game
				globalWindow.PreferenceRegisterExtensionSetting(CRABS_Base.subscreenDef);
			} else {
				setTimeout(waitForFunc, 1000);
			}
		};
		waitForFunc();
	}

	/**
	 * Renders the settings screen UI.
	 * 
	 * @returns {void}
	 */
	public draw(): void {
		const isMouseIn = (window as any).MouseIn;
		const DrawText = (window as any).DrawText;
		const DrawCheckbox = (window as any).DrawCheckbox;
		const DrawCharacter = (window as any).DrawCharacter;
		const DrawRect = (window as any).DrawRect;
		const PreferenceMessage = (window as any).PreferenceMessage;
		const DrawButton = (window as any).DrawButton;
		const DrawBackNextButton = (window as any).DrawBackNextButton;

		const DrawBackNext = (Left: number, Top: number, Width: number, Height: number, Text: string, Value: string, Disabled: boolean) => {
			DrawBackNextButton(Left, Top, Width, Height, Text + ": " + Value, Disabled ? "Gray" : "White", "", null, null, Disabled);
		};

		const canvasElement = document.getElementById("MainCanvas") as HTMLCanvasElement;
		const canvasContext = canvasElement ? canvasElement.getContext("2d") : null;
		if (!canvasContext) return;

		// Draw character background card
		DrawRect(40, 40, 420, 920, "#222222aa");
		DrawCharacter((window as any).Player, 50, 50, 0.9);
		canvasContext.textAlign = "center";
		canvasContext.textBaseline = "middle";

		// Main Header
		DrawText(i18n.get("CRABS_Mod_Settings"), 1000, 80, "Black", "Gray");
		DrawButton(1815, 75, 90, 90, "", "White", "Icons/Exit.png", i18n.get("Back_To_Extensions"));

		if (PreferenceMessage && PreferenceMessage !== "") {
			DrawText(PreferenceMessage, 1000, 150, "Red", "Black");
		}

		const leftCenterX = (this.LEFT_COL_X - 20) + (650 / 2);
		const rightCenterX = (this.RIGHT_COL_X - 20) + (650 / 2);

		// Draw Section Cards
		DrawRect(this.LEFT_COL_X - 20, 150, 650, 200, "#00000011");
		DrawText(i18n.get("Category_Language"), leftCenterX, 170, "Black", "Gray");

		DrawRect(this.LEFT_COL_X - 20, 380, 650, 125, "#00000011");
		DrawText(i18n.get("Category_Banner"), leftCenterX, 400, "Black", "Gray");

		DrawRect(this.LEFT_COL_X - 20, 525, 650, 350, "#00000011");
		DrawText(i18n.get("Category_Drawer"), leftCenterX, 545, "Black", "Gray");

		DrawRect(this.RIGHT_COL_X - 20, 150, 650, 350, "#00000011");
		DrawText(i18n.get("Category_Immersion"), rightCenterX, 170, "Black", "Gray");

		DrawRect(this.RIGHT_COL_X - 20, 520, 650, 200, "#00000011");
		DrawText(i18n.get("Category_Maps"), rightCenterX, 540, "Black", "Gray");

		for (const element of this.elements) {
			const isRightCol = element.category === "Immersion" || element.category === "Maps";
			const cardX = isRightCol ? this.RIGHT_COL_X : this.LEFT_COL_X;
			const y = element.yPos;
			const checkboxX = cardX + this.CHECKBOX_X_OFFSET;
			const textX = cardX + this.LABEL_X_OFFSET;

			const isGrayedOut = (typeof element.grayedOut === 'function' ? element.grayedOut() : element.grayedOut) || false;

			if (element.type === 'Checkbox') {
				DrawCheckbox(checkboxX, y - 32, 64, 64, "", (this.data as any)[element.setting], isGrayedOut);

				// Align left, then use native DrawText so the theme mod can intercept "Black"
				canvasContext.textAlign = "left";
				DrawText(element.text, textX, y, isGrayedOut ? "gray" : "Black", "");

				if (isMouseIn(textX, y - 18, 450, 36) || isMouseIn(checkboxX, y - 32, 64, 64)) {
					canvasContext.textAlign = "center";
					DrawText(element.hint, 1100, 950, "Black", "Gray");
				}
			} else if (element.type === 'BackNext') {
				DrawBackNext(checkboxX, y - 32, 450, 64, element.text, (this.data as any)[element.setting], isGrayedOut);
				if (isMouseIn(checkboxX, y - 32, 450, 64)) {
					canvasContext.textAlign = "center";
					DrawText(element.hint, 1100, 950, "Black", "Gray");
				}
			}
		}

		canvasContext.textAlign = "center";
		canvasContext.textBaseline = "alphabetic";
	}

	/**
	 * Handles click events on the settings screen.
	 * 
	 * @returns {void}
	 */
	public click(): void {
		const isMouseIn = (window as any).MouseIn;

		if (isMouseIn(1815, 75, 90, 90)) {
			(window as any).PreferenceMessage = "";
			(window as any).PreferenceSubscreenExtensionsClear();
			return;
		}

		for (const element of this.elements) {
			const isRightCol = element.category === "Immersion" || element.category === "Maps";
			const cardX = isRightCol ? this.RIGHT_COL_X : this.LEFT_COL_X;
			const y = element.yPos;
			const checkboxX = cardX + this.CHECKBOX_X_OFFSET;

			const isGrayedOut = (typeof element.grayedOut === 'function' ? element.grayedOut() : element.grayedOut) || false;
			if (isGrayedOut) continue;

			if (element.type === 'Checkbox' && isMouseIn(checkboxX, y - 32, 450, 64)) {
				(this.data as any)[element.setting] = !(this.data as any)[element.setting];

				if (element.setting === "disableDrawer" && this.data.disableDrawer) {
					this.data.rosterOpensDrawer = false;
					this.data.hideDrawerTab = false;
				}
				if (element.setting === "rosterOpensDrawer" && this.data.rosterOpensDrawer) {
					this.data.disableDrawer = false;
				}

				if (element.setting === "rosterOpensDrawer" && !this.data.rosterOpensDrawer) {
					this.data.hideDrawerTab = false;
				}

				this.save();
				this.syncGameState();
				return;
			} else if (element.type === 'BackNext' && isMouseIn(checkboxX, y - 32, 450, 64)) {
				const direction = (isMouseIn(checkboxX, y - 32, 225, 64) ? -1 : 1);
				const options = element.backNextOptions;
				let index = options.indexOf((this.data as any)[element.setting]);
				index = (index + direction + options.length) % options.length;
				(this.data as any)[element.setting] = options[index];

				this.save();
				return;
			}
		}
	}

	/**
	 * Synchronizes mod settings with the game's internal variables.
	 * 
	 * @returns {void}
	 */
	public syncGameState(): void {
		const globalWindow = window as any;
		// Apply SuperZoom setting
		if (this.data.mapSuperZoom) {
			globalWindow.ChatRoomMapViewPerceptionRangeMax = 50;
		} else {
			// Restore default (Bondage Club default is typically 4)
			globalWindow.ChatRoomMapViewPerceptionRangeMax = 4;
		}
	}
}
