import { en, TranslationKeys } from "./en";
import { fr } from "./fr";
import { ru } from "./ru";
import { zh } from "./zh";
import { zh_tw } from "./zh_tw";
import { uk } from "./uk";

export type LanguageCode = "en" | "fr" | "ru" | "zh" | "zh_tw" | "uk";

const translations: Record<LanguageCode, Partial<Record<TranslationKeys, string>>> = {
    en,
    fr,
    ru,
    zh,
    zh_tw,
    uk,
};

class LocalizationManager {
    private static instance: LocalizationManager;
    private currentLanguage: LanguageCode = "en";

    private constructor() {}

    public static getInstance(): LocalizationManager {
        if (!LocalizationManager.instance) {
            LocalizationManager.instance = new LocalizationManager();
        }
        return LocalizationManager.instance;
    }

    public setLanguage(lang: LanguageCode): void {
        this.currentLanguage = lang;
    }

    public getLanguage(): LanguageCode {
        return this.currentLanguage;
    }

    /**
     * Maps Bondage Club's TranslationLanguage to a supported CRABS language code.
     */
    public detectGameLanguage(): LanguageCode {
        const gameLang = (window as any).TranslationLanguage;
        switch (gameLang) {
            case "FR": return "fr";
            case "RU": return "ru";
            case "CN": return "zh";
            case "TW": return "zh_tw";
            case "UK": return "uk";
            default: return "en";
        }
    }

    public get(key: TranslationKeys, params: Record<string, string> = {}): string {
        const langDict = translations[this.currentLanguage] || translations.en;
        let text = langDict[key] || en[key] || key;

        for (const [param, value] of Object.entries(params)) {
            text = text.replace(`{${param}}`, value);
        }

        return text;
    }

    /**
     * Translates an entire HTML string by replacing {{Key}} with the localized value.
     */
    public translateHtml(html: string): string {
        return html.replace(/\{\{([^}]+)\}\}/g, (match, key) => {
            if (key in en) {
                return this.get(key as TranslationKeys);
            }
            return match;
        });
    }
}

export const i18n = LocalizationManager.getInstance();
